class Solution(object):
    def beautifulNumbers(self, l, r):
        """
        :type l: int
        :type r: int
        :rtype: int
        """
        def count_beautiful(num_str):
            """Count beautiful numbers <= num_str"""
            memo = {}

            def dp(pos, product, digit_sum, tight):
                if pos == len(num_str):
                    if digit_sum == 0:
                        return 0  # Avoid division by zero
                    return 1 if product % digit_sum == 0 else 0

                if (pos, product, digit_sum, tight) in memo:
                    return memo[(pos, product, digit_sum, tight)]

                limit = int(num_str[pos]) if tight else 9
                result = 0

                for digit in range(0, limit + 1):
                    new_product = product * digit if digit > 0 else product
                    new_sum = digit_sum + digit
                    new_tight = tight and (digit == limit)

                    result += dp(pos + 1, new_product, new_sum, new_tight)

                memo[(pos, product, digit_sum, tight)] = result
                return result

            return dp(0, 1, 0, True)

        return count_beautiful(str(r)) - count_beautiful(str(l - 1))
